    //numéro du calcul
    let tab = ["1_battChargeWatt", "2_battDechargeWatt", "3_battChargeDechargeWatt"]


    let payload = msg.payload
    let count = tab.length //compte le nombre du tableau 


    for (let i = 1; i <= count; i++) {

        /*-------------------------------------------------*/
        //1 Batterie charge en watt
        /*-------------------------------------------------*/
        if (i == 1) {

            //calcul
            let charge = payload[9] * payload[8];
            msg.payload = charge.toFixed(2);
        }

        /*-------------------------------------------------*/
        //2 Batterie Decharge en watt
        /*-------------------------------------------------*/
        if (i == 2) {

            //calcul
            let decharge = payload[15] * payload[8];
            msg.payload = decharge.toFixed(2);
        }

        //nouveau Parametre pour mqtt en custom
        msg.topic = global.get("parametre.mqtt.DirSmart") + '/' + global.get("onduleurs.onduleur_" + msg.voltronicNum + ".type") + '_' + msg.voltronicNum + '/' + name + i;
        node.send(msg);

        /*-------------------------------------------------*/
        //3 Batterie charge positive, Decharge négative en watt
        /*-------------------------------------------------*/
        if (i == 3) {

            let charge = payload[9] * payload[8];
            let decharge = payload[15] * payload[8];

            if (charge >= 0 && decharge == 0) {

                msg.payload = charge.toFixed(2);

            }else if (charge == 0 && decharge >= 0){

                decharge = -decharge;
                msg.payload = decharge.toFixed(2);

            }else{

                msg.payload = 0;

            }

        }
        //nouveau Parametre pour mqtt en custom
        msg.topic = global.get("parametre.mqtt.DirSmart") + '/' + global.get("onduleurs.onduleur_" + msg.voltronicNum + ".type") + '_' + msg.voltronicNum + '/' + name + i;
