function createMessage(command, voltronicNum) {
    // Encode la commande en HEX et ajoute le CRC
    let commandHex = Buffer.from(command).toString('hex');
    let crc = crc16(command).toString(16); // Calcul du CRC16
    let messageHex = commandHex + crc + "0D"; // Ajout du CRC et du retour chariot
    return Buffer.from(messageHex, "hex");
}

// Fonction de calcul CRC16 XModem
function crc16(str, crc = 0, xorout = 0) {
    for (let i = 0, t; i < str.length; i++, crc &= 0xFFFF) {
        t = (crc >> 8) ^ str.charCodeAt(i);
        t ^= t >> 4;
        crc = (crc << 8) ^ (t << 12) ^ (t << 5) ^ t;
    }
    return crc ^ xorout;
}






