    // Réinitialiser la variable d'alerte
    flow.set("alerteEnvoyee", false);

    setTimeout(function () {
        // Mise à jour de l'heure du dernier message avant envoi
        flow.set("dernierMessageTemps_" + msg.voltronicNum, Date.now());

        // Envoyer le message
        node.send(msg);

    }, global.get("parametre.config.interval") * 1000);  // intervalle en secondes

}

