    "SOH Times", "BMICERR Times", "CYCLE Times", "SOH", "Pwr Percent", "Pwr Coulomb", "Dsg Cap",
    "HT@0.5C Cnt", "LT@0.5C Cnt", "HT Cnt", "LT Cnt", "LV Cnt", "LifeWarn Times", "LifeAlarm Times"
];

// Création d'un objet result pour stocker les valeurs extraites
let result = {};

dataLabels.forEach(function(label) {
    // Trouver l'index de la ligne contenant le label
    let index = payload.findIndex(function(item) {
        return item.indexOf(label) !== -1;
    });

    // Si l'index est trouvé, extraire la valeur
    if (index !== -1) {
        let value = payload[index];

        // Nettoyer la valeur (enlever les espaces, les retours à la ligne)
        value = value.split(' ').join('');
        value = value.replace(label, '').replace(/[\r\n]+/gm, "").trim();

        // Extraire la valeur après le ":", et transformer en nombre si possible
        let [key, val] = value.split(":");
        val = isNaN(val) ? val : Number(val); // Si la valeur est numérique, la convertir en nombre

        // Stocker dans l'objet result
        result[label] = val;
    }
});

